/*
* Recursion/DFS + memoization
*/
class Solution {
    fun countGoodStrings(low: Int, high: Int, zero: Int, one: Int): Int {
        val dp = IntArray(high + 1) { -1 }
        val mod = 1000000007

        fun dfs(i: Int): Int {
            if (i > high) 
                return 0
            if (dp[i] != -1)
                return dp[i]

            dp[i] = if (i >= low) 1 else 0
            dp[i] += dfs(i + zero) + dfs(i + one)
            dp[i] = dp[i] % mod

            return dp[i]
        }

        return dfs(0)
    }
}

