class Solution {
    fun countGoodStrings(low: Int, high: Int, zero: Int, one: Int): Int {
        val dp = IntArray(high + 1)
        val mod = 1000000007

        dp[0] = 1
        for (i in 1..high) {
            dp[i] += if (i - one >= 0) dp[i - one] else 0
            dp[i] += if (i - zero >= 0) dp[i - zero] else 0
            dp[i] = dp[i] % mod
        }

        var sum = 0
        for (i in low..high) sum = (sum + dp[i]) % mod
        return sum
    }
}

